DELETE FROM wp_postmeta WHERE post_id = 100824 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100824, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === EVENT HERO === */\n.iat-hero-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:140px 24px 80px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-hero-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.iat-hero-section>*{position:relative;z-index:2}\n.iat-hero-back{display:inline-flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:500;color:rgba(255,255,255,0.85);text-decoration:none;margin-bottom:24px;transition:color 0.3s ease}\n.iat-hero-back:hover{color:rgba(255,255,255,0.9)}\n.iat-hero-badge{display:inline-flex;align-items:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:1.5px;color:#0891b2;background:rgba(8,145,178,0.15);padding:6px 18px;border:1px solid rgba(8,145,178,0.3);border-radius:50px;margin-bottom:20px}\n.iat-hero-section h1{font-family:\'Noto Sans\',sans-serif;font-size:clamp(28px,4.5vw,44px);font-weight:700;color:#fff;line-height:1.2;max-width:800px;margin:0 auto 20px;padding:0}\n.iat-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 auto 40px;padding:0}\n.iat-hero-facts{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;max-width:700px;margin:0 auto 40px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:24px}\n.iat-hero-fact{text-align:center}\n.iat-hero-fact-icon{margin-bottom:8px}\n.iat-hero-fact-icon svg{stroke:#0891b2}\n.iat-hero-fact-value{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff}\n.iat-hero-fact-label{font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.85)}\n.iat-hero-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff;background:#0891b2;padding:16px 40px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(8,145,178,0.4)}\n.iat-hero-cta:hover{background:rgb(57,167,193);transform:translateY(-2px);box-shadow:0 8px 24px rgba(8,145,178,0.3)}\n\n.et_pb_section .iat-hero-section h1{-webkit-font-smoothing:auto !important;line-height:1.2 !important;max-width:800px !important;margin:0 auto 20px !important;padding:0 !important}\n.et_pb_section .iat-hero-subtitle{-webkit-font-smoothing:auto !important}\n.et_pb_section .iat-hero-fact-value{-webkit-font-smoothing:auto !important;line-height:25.6px !important;margin-bottom:4px !important}\n.et_pb_section .iat-hero-fact-label{-webkit-font-smoothing:auto !important;line-height:20.8px !important}\n.et_pb_section .iat-hero-badge{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-hero-cta{-webkit-font-smoothing:auto !important;line-height:25.6px !important}\n.et_pb_section .iat-hero-back{-webkit-font-smoothing:auto !important}\n.iat-hero-superd{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.12;pointer-events:none;z-index:0}\n\n@media(max-width:768px){\n  .iat-hero-section{padding:120px 20px 60px}\n  .iat-hero-facts{grid-template-columns:repeat(2,1fr);gap:20px}\n}\n@media(max-width:480px){\n  .iat-hero-facts{grid-template-columns:1fr}\n  .iat-hero-cta{width:100%;justify-content:center}\n}\n@media(prefers-reduced-motion:reduce){.iat-hero-section *{transition:none !important}}\n/* === EVENT BANNER === */\n.iat-ban-section{background:linear-gradient(180deg,#000864 0%,#0a1a3a 15%,#1a2a4a 30%,#fff 70%,#fff 100%);padding:40px 24px 60px;margin-top:-40px;position:relative;z-index:3;text-align:center}\n.iat-ban-inner{max-width:900px;margin:0 auto;padding-top:0}\n.iat-ban-img{width:100%;height:auto;border-radius:16px;display:block;box-shadow:0 12px 40px rgba(0,8,100,0.25),0 4px 12px rgba(0,0,0,0.1);border:1px solid rgba(255,255,255,0.08)}\n\n.et_pb_section .iat-ban-section{padding-top:40px !important;margin-top:-40px !important}\n\n@media(max-width:768px){\n  .iat-ban-section{padding:24px 16px 40px;margin-top:-24px}\n  .iat-ban-img{border-radius:12px}\n  .et_pb_section .iat-ban-section{margin-top:-24px !important}\n}\n@media(max-width:480px){\n  .iat-ban-section{padding:16px 12px 32px;margin-top:-16px}\n  .iat-ban-img{border-radius:8px}\n  .et_pb_section .iat-ban-section{margin-top:-16px !important}\n}\n/* === THE PROBLEM === */\n.iat-prob-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-prob-inner{text-align:center;max-width:800px;margin:0 auto 40px}\n.iat-prob-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;display:block;margin-bottom:16px}\n.iat-prob-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-prob-body{max-width:800px;margin:0 auto}\n.iat-prob-body p{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#333;line-height:1.8;margin:0 0 24px;padding:0}\n.iat-prob-body strong{font-weight:600;color:#000864}\n.iat-prob-data-card{background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px;margin:32px 0;text-align:center;position:relative;overflow:hidden}\n.iat-prob-data-card::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none}\n.iat-prob-data-content{position:relative;z-index:2}\n.iat-prob-data-number{font-family:\'JetBrains Mono\',monospace;font-size:48px;font-weight:500;color:#00AFF0;line-height:1.2;margin-bottom:8px}\n.iat-prob-data-arrow{font-size:32px;color:rgba(255,255,255,0.85);line-height:1.6;margin:4px 0}\n.iat-prob-data-number--success{color:#0891b2}\n.iat-prob-data-label{font-family:\'Noto Sans\',sans-serif;font-size:16px;color:rgba(255,255,255,0.9);margin-top:12px}\n.iat-prob-case-link{text-align:center;margin-top:32px}\n.iat-prob-case-link a{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#0891b2;text-decoration:none;transition:color 0.3s ease}\n.iat-prob-case-link a:hover{color:rgb(57,167,193)}\n\n.et_pb_section .iat-prob-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-prob-body p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .iat-prob-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-prob-data-number{-webkit-font-smoothing:auto !important;line-height:57.6px !important}\n.et_pb_section .iat-prob-data-label{-webkit-font-smoothing:auto !important}\n.et_pb_section .iat-prob-case-link{-webkit-font-smoothing:auto !important;margin-top:32px !important;padding-bottom:0 !important}\n.et_pb_section .iat-prob-case-link a{-webkit-font-smoothing:auto !important;line-height:27px !important}\n\n@media(max-width:768px){\n  .iat-prob-title{font-size:28px}\n  .iat-prob-body p{font-size:16px}\n  .iat-prob-data-number{font-size:24px}\n}\n@media(prefers-reduced-motion:reduce){.iat-prob-section *{transition:none !important}}\n/* === OUTCOMES === */\n.iat-out-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-out-inner{max-width:1100px;margin:0 auto}\n.iat-out-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;margin-bottom:16px}\n.iat-out-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-out-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.iat-out-card{background:#fff;border-radius:16px;padding:32px;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.iat-out-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.iat-out-icon{width:48px;height:48px;border-radius:50%;background:rgba(8,145,178,0.1);display:flex;align-items:center;justify-content:center;margin-bottom:16px}\n.iat-out-icon svg{stroke:#0891b2}\n.iat-out-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px;padding:0}\n.iat-out-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n\n.et_pb_section .iat-out-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-out-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-out-card h3{-webkit-font-smoothing:auto !important;margin:0 0 8px !important;padding:0 !important}\n.et_pb_section .iat-out-card p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .iat-out-grid{grid-template-columns:1fr}\n  .iat-out-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.iat-out-card{transition:none !important}}\n/* === WHO SHOULD ATTEND === */\n.iat-per-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-per-inner{max-width:1100px;margin:0 auto}\n.iat-per-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;margin-bottom:16px}\n.iat-per-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-per-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.iat-per-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.iat-per-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.iat-per-accent{height:4px;background:#0891b2}\n.iat-per-body{padding:28px}\n.iat-per-role{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#000864;line-height:1.6;margin-bottom:8px}\n.iat-per-size{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;background:rgba(8,145,178,0.1);padding:4px 10px;border-radius:4px;margin-bottom:16px}\n.iat-per-desc{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0 0 16px;padding:0}\n.iat-per-quote{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:#5b6b80;font-style:italic;line-height:1.6;margin:0;padding:16px 0 0;border-top:1px solid #f1f5f9}\n\n.et_pb_section .iat-per-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-per-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-per-role{-webkit-font-smoothing:auto !important;line-height:32px !important}\n.et_pb_section .iat-per-size{-webkit-font-smoothing:auto !important;line-height:17.6px !important}\n.et_pb_section .iat-per-desc{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .iat-per-quote{-webkit-font-smoothing:auto !important;padding-bottom:0 !important;line-height:22.4px !important}\n\n@media(max-width:1024px){\n  .iat-per-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .iat-per-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.iat-per-card{transition:none !important}}\n/* === PROOF / SOCIAL SIGNAL === */\n.iat-prf-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-prf-inner{max-width:1100px;margin:0 auto;text-align:center}\n.iat-prf-label{display:block;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;margin-bottom:16px}\n.iat-prf-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-prf-stats-bar{display:grid;grid-template-columns:repeat(4,1fr);gap:0;background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px 32px;margin-bottom:40px}\n.iat-prf-stat{text-align:center;padding:0 16px}\n.iat-prf-stat:not(:last-child){border-right:1px solid rgba(255,255,255,0.1)}\n.iat-prf-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#0891b2;line-height:1;margin-bottom:8px}\n.iat-prf-stat-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:rgba(255,255,255,0.85);margin-top:0}\n.iat-prf-text{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.8;max-width:700px;margin:0 auto;padding:0}\n\n.et_pb_section .iat-prf-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-prf-text{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .iat-prf-stat-value{-webkit-font-smoothing:auto !important;line-height:1 !important;margin-bottom:8px !important}\n.et_pb_section .iat-prf-stat-label{-webkit-font-smoothing:auto !important;line-height:22.4px !important;margin-top:0 !important}\n.et_pb_section .iat-prf-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-prf-stat{-webkit-font-smoothing:auto !important}\n.et_pb_section .iat-prf-stats-bar{margin-bottom:40px !important}\n\n@media(max-width:768px){\n  .iat-prf-stats-bar{grid-template-columns:repeat(2,1fr);gap:24px}\n  .iat-prf-stat:not(:last-child){border-right:none}\n  .iat-prf-stat:nth-child(odd){border-right:1px solid rgba(255,255,255,0.1)}\n  .iat-prf-title{font-size:28px}\n  .iat-prf-stat-value{font-size:32px}\n}\n@media(max-width:480px){\n  .iat-prf-stats-bar{grid-template-columns:1fr}\n  .iat-prf-stat:nth-child(odd){border-right:none}\n}\n@media(prefers-reduced-motion:reduce){.iat-prf-section *{transition:none !important}}\n/* === LOGISTICS === */\n.iat-log-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-log-inner{max-width:900px;margin:0 auto}\n.iat-log-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0891b2;margin-bottom:16px}\n.iat-log-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.iat-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.iat-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.iat-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(8,145,178,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.iat-log-icon svg{stroke:#0891b2}\n.iat-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.iat-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .iat-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .iat-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .iat-log-item-label,.et_pb_section .iat-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .iat-log-grid{grid-template-columns:1fr}\n  .iat-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.iat-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.iat-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.iat-reg-section::befo